        if (client_fd < 0) continue;

        std::lock_guard<std::mutex> lock(threads_mutex);
        active_threads.emplace_back(handle_client, client_fd);
    }

    // Join all threads before exit
    for (auto& t : active_threads) {
        if (t.joinable()) t.join();
    }

    close(server_fd);
    return 0;
}

