    fcntl(fd, F_SETFL, flags | O_NONBLOCK);
}

int main() {
    // Create server socket
    int server_fd = socket(AF_INET, SOCK_STREAM, 0);
    if (server_fd < 0) {
        perror("socket");
        return 1;
    }

    int opt = 1;
    setsockopt(server_fd, SOL_SOCKET, SO_REUSEADDR, &opt, sizeof(opt));

    struct sockaddr_in server_addr;
    server_addr.sin_family = AF_INET;
    server_addr.sin_addr.s_addr = INADDR_ANY;
    server_addr.sin_port = htons(PORT);

    if (bind(server_fd, (struct sockaddr*)&server_addr, sizeof(server_addr)) < 0) {
        perror("bind");
        close(server_fd);
        return 1;
    }

    if (listen(server_fd, 128) < 0) {
        perror("listen");
        close(server_fd);
        return 1;
    }

    set_nonblocking(server_fd);

    std::cout << "Echo server listening on port " << PORT << " (epoll level-triggered)\n";

    // Create epoll instance
    int epfd = epoll_create1(0);
    if (epfd < 0) {
        perror("epoll_create1");
        close(server_fd);
        return 1;
    }

    // Add server socket to epoll
    struct epoll_event ev, events[MAX_EVENTS];
    ev.events = EPOLLIN;
    ev.data.fd = server_fd;

    if (epoll_ctl(epfd, EPOLL_CTL_ADD, server_fd, &ev) < 0) {
        perror("epoll_ctl");
        close(server_fd);
        close(epfd);
        return 1;
    }

    // Event loop
    while (true) {
        int nready = epoll_wait(epfd, events, MAX_EVENTS, -1);

        if (nready < 0) {
            perror("epoll_wait");
            break;
        }

        for (int i = 0; i < nready; i++) {
            int fd = events[i].data.fd;

            if (fd == server_fd) {
                // New connection
                struct sockaddr_in client_addr;
                socklen_t addr_len = sizeof(client_addr);
                int client_fd = accept(server_fd, (struct sockaddr*)&client_addr, &addr_len);

                if (client_fd < 0) {
                    perror("accept");
                    continue;
                }

                set_nonblocking(client_fd);

                // Add to epoll
                ev.events = EPOLLIN;
                ev.data.fd = client_fd;
                epoll_ctl(epfd, EPOLL_CTL_ADD, client_fd, &ev);

                std::cout << "Client " << client_fd << " connected\n";
            }
            else {
                // Client data
                if (events[i].events & EPOLLIN) {
                    char buffer[BUFFER_SIZE];
                    int n = recv(fd, buffer, sizeof(buffer), 0);

                    if (n <= 0) {
                        // Client disconnected or error
                        if (n == 0) {
                            std::cout << "Client " << fd << " disconnected\n";
                        } else {
                            perror("recv");
                        }

                        epoll_ctl(epfd, EPOLL_CTL_DEL, fd, NULL);
                        close(fd);
                    }
                    else {
                        // Echo back
                        buffer[n] = '\0';
                        std::cout << "Client " << fd << ": " << buffer;
                        send(fd, buffer, n, 0);
                    }
                }

                if (events[i].events & (EPOLLHUP | EPOLLERR)) {
                    std::cout << "Client " << fd << " error/hangup\n";
                    epoll_ctl(epfd, EPOLL_CTL_DEL, fd, NULL);
                    close(fd);
                }
            }
        }
    }

    close(epfd);
    close(server_fd);
    return 0;
}

#include <iostream>
#include <sys/epoll.h>
#include <sys/socket.h>
#include <netinet/in.h>
#include <unistd.h>
#include <fcntl.h>
#include <cstring>
#include <errno.h>

const int PORT = 8080;
const int MAX_EVENTS = 128;
const int BUFFER_SIZE = 1024;

void set_nonblocking(int fd) {
    int flags = fcntl(fd, F_GETFL, 0);
    fcntl(fd, F_SETFL, flags | O_NONBLOCK);
}

int main() {
    // Create server (same as Example 1)
    int server_fd = socket(AF_INET, SOCK_STREAM, 0);
    int opt = 1;
    setsockopt(server_fd, SOL_SOCKET, SO_REUSEADDR, &opt, sizeof(opt));

    struct sockaddr_in server_addr;
    server_addr.sin_family = AF_INET;
    server_addr.sin_addr.s_addr = INADDR_ANY;
    server_addr.sin_port = htons(PORT);

    bind(server_fd, (struct sockaddr*)&server_addr, sizeof(server_addr));
    listen(server_fd, 128);
    set_nonblocking(server_fd);

    std::cout << "Echo server on port " << PORT << " (EDGE-TRIGGERED)\n";

    // Create epoll with edge-triggered
    int epfd = epoll_create1(0);
    struct epoll_event ev, events[MAX_EVENTS];

    // Add server with EPOLLET
    ev.events = EPOLLIN | EPOLLET;
    ev.data.fd = server_fd;
    epoll_ctl(epfd, EPOLL_CTL_ADD, server_fd, &ev);

    while (true) {
        int nready = epoll_wait(epfd, events, MAX_EVENTS, -1);

        for (int i = 0; i < nready; i++) {
            int fd = events[i].data.fd;

            if (fd == server_fd) {
                // Accept ALL pending connections (edge-triggered)
                while (true) {
                    struct sockaddr_in client_addr;
                    socklen_t addr_len = sizeof(client_addr);
                    int client_fd = accept(server_fd, (struct sockaddr*)&client_addr, &addr_len);

                    if (client_fd < 0) {
                        if (errno == EAGAIN || errno == EWOULDBLOCK) {
                            break;  // No more pending connections
                        }
                        perror("accept");
                        break;
                    }

                    set_nonblocking(client_fd);

                    // Add with edge-triggered
                    ev.events = EPOLLIN | EPOLLET;
                    ev.data.fd = client_fd;
                    epoll_ctl(epfd, EPOLL_CTL_ADD, client_fd, &ev);

                    std::cout << "Client " << client_fd << " connected\n";
                }
            }
            else {
                if (events[i].events & EPOLLIN) {
                    // Read ALL available data (critical for edge-triggered!)
                    while (true) {
                        char buffer[BUFFER_SIZE];
                        int n = recv(fd, buffer, sizeof(buffer), 0);

                        if (n < 0) {
                            if (errno == EAGAIN || errno == EWOULDBLOCK) {
                                break;  // ✅ All data read
                            }

                            // Real error
                            perror("recv");
                            epoll_ctl(epfd, EPOLL_CTL_DEL, fd, NULL);
                            close(fd);
                            break;
                        }

                        if (n == 0) {
                            // EOF
                            std::cout << "Client " << fd << " disconnected\n";
                            epoll_ctl(epfd, EPOLL_CTL_DEL, fd, NULL);
                            close(fd);
                            break;
                        }

                        // Echo back
                        buffer[n] = '\0';
                        std::cout << "Client " << fd << ": " << buffer;
                        send(fd, buffer, n, MSG_NOSIGNAL);
                    }
                }

                if (events[i].events & (EPOLLHUP | EPOLLERR)) {
                    epoll_ctl(epfd, EPOLL_CTL_DEL, fd, NULL);
                    close(fd);
                }
            }
        }
    }

    close(epfd);
    close(server_fd);
    return 0;
}

#include <iostream>
#include <map>
#include <string>
#include <sys/epoll.h>
#include <sys/socket.h>
