epoll_ctl(epfd, EPOLL_CTL_ADD, listen_fd, &ev);

int opt = 1;
setsockopt(listen_fd, SOL_SOCKET, SO_REUSEPORT, &opt, sizeof(opt));

// Each process binds to same port
bind(listen_fd, ...);  // All processes bind to :8080
listen(listen_fd, 128);

