        cpu_set_t cpuset;
        CPU_ZERO(&cpuset);
        CPU_SET(i, &cpuset);
        pthread_setaffinity_np(pthread_self(), sizeof(cpuset), &cpuset);

        // Event loop (fully independent!)
        while (true) {
            struct epoll_event events[128];
            int n = epoll_wait(epfd, events, 128, -1);

            for (int j = 0; j < n; j++) {
                handle_event(events[j]);
            }
        }
    }).detach();
}

