    while (!draining) {
        // epoll_wait continues accepting new connections!
        int client_fd = accept(listen_fd, NULL, NULL);
        handle_request(client_fd);
    }

    // Wait for drain
    while (in_flight.load() > 0) {
        sleep(1);
    }
}

